  { key: "sizeLength", description: "Size: Length" },
  { key: "sizeWidth", description: "Size: Width" },
  { key: "length", description: "Length" },
];

type TestResultData = { 
  analysisInitial?: string; 
  analysisFinal?: string;
  descriptionInitial?: string;
  descriptionFinal?: string;
};

interface JobData {
  status: "pending" | "running" | "completed" | "failed" | "canceled";
  result?: TestResultData & { analysis?: string; description?: string };
  errorMessage?: string;
}

export function AiDescriptionSettings(): React.JSX.Element {
  const [imageAnalysisModel, setImageAnalysisModel] = useState("");

  // Path 1
  const [visionInputPrompt, setVisionInputPrompt] = useState("");
  const [visionOutputPrompt, setVisionOutputPrompt] = useState("");
  const [visionOutputEnabled, setVisionOutputEnabled] = useState(false);

  const [descriptionGenerationModel, setDescriptionGenerationModel] = useState("");

  // Path 2
  const [generationInputPrompt, setGenerationInputPrompt] = useState("");
  const [generationOutputPrompt, setGenerationOutputPrompt] = useState("");
  const [generationOutputEnabled, setGenerationOutputEnabled] = useState(false);

  const [ollamaModels, setOllamaModels] = useState<{ value: string; label: string; description: string }[]>([]);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const { toast } = useToast();

  const [testProductId, setTestProductId] = useState("");
  const [testing, setTesting] = useState(false);
  const [testResult, setTestResult] = useState<TestResultData | null>(null);
  const [queuing, setQueuing] = useState(false);

  // Use TanStack Query hooks
  const settingsStore = useSettingsStore();
  const settingsMap = settingsStore.map;
  const settingsLoading = settingsStore.isLoading;
  const { mutateAsync: updateSettingMutateAsync } = useUpdateSetting();

  useEffect(() => {
    if (settingsMap && !settingsLoading) {
      setImageAnalysisModel(settingsMap.get("ai_vision_model") || "gpt-4o");
      setVisionInputPrompt(settingsMap.get("ai_vision_user_prompt") || "Analyze these product images...");
      setVisionOutputPrompt(settingsMap.get("ai_vision_prompt") || "");
      setVisionOutputEnabled(settingsMap.get("ai_vision_output_enabled") === "true");
      setDescriptionGenerationModel(settingsMap.get("ai_description_model") || "gpt-4o");
      setGenerationInputPrompt(settingsMap.get("ai_description_user_prompt") || "Generate a product description...");
      setGenerationOutputPrompt(settingsMap.get("ai_description_prompt") || "");
      setGenerationOutputEnabled(settingsMap.get("ai_description_output_enabled") === "true");
      setLoading(false);
    }
  }, [settingsMap, settingsLoading]);

  useEffect(() => {
    const loadData = async (): Promise<void> => {
      try {
        const data = await fetchSettingsCached();
        const settingsMap = new Map(data.map((item: SettingRecord) => [item.key, item.value]));

        setImageAnalysisModel(settingsMap.get("ai_vision_model") || "gpt-4o");
        setVisionInputPrompt(settingsMap.get("ai_vision_user_prompt") || "Analyze these product images...");
        setVisionOutputPrompt(settingsMap.get("ai_vision_prompt") || "");
        setVisionOutputEnabled(settingsMap.get("ai_vision_output_enabled") === "true");

        setDescriptionGenerationModel(settingsMap.get("openai_model") || "gpt-3.5-turbo");
        setGenerationInputPrompt(settingsMap.get("description_generation_user_prompt") || "Generate description for [name_en] using [result]");
        setGenerationOutputPrompt(settingsMap.get("description_generation_prompt") || "");
        setGenerationOutputEnabled(settingsMap.get("ai_generation_output_enabled") === "true");
        setTestProductId(settingsMap.get("ai_description_test_product_id") || "");

        // Load last test result if exists
        const testResultJson = settingsMap.get("ai_description_last_test_result");
        if (testResultJson) {
          try {
            const parsed = JSON.parse(testResultJson) as TestResultData;
            setTestResult(parsed);
            console.log("Loaded previous test result from database");
          } catch (err) {
            console.warn("Failed to parse saved test result:", err);
          }
        }

        const chatbotRes = await fetch("/api/chatbot");
        if (chatbotRes.ok) {
          const data = (await chatbotRes.json()) as { models?: string[] };
          if (Array.isArray(data.models)) {
            setOllamaModels(data.models.map((name: string) => ({ value: name, label: name, description: "Ollama" })));
          }
        }
      } catch (error) {
        logClientError(error, { context: { source: "AiDescriptionSettings", action: "loadData" } });
        toast("Failed to load configuration.", { variant: "error" });
      } finally {
        setLoading(false);
      }
    };
    void loadData();
  }, [toast]);

  const handleTest = async (): Promise<void> => {
    if (!testProductId) {
      toast("Please enter a Product ID or SKU.", { variant: "error" });
      return;
    }

    setTesting(true);
    setTestResult(null);

    try {
      let product: ProductWithImages | null = null;
      const productRes = await fetch(`/api/products/${testProductId}`);

      if (productRes.ok) {
        product = (await productRes.json()) as ProductWithImages;
      } else {
        const skuRes = await fetch(`/api/products?sku=${testProductId}`);
        if (skuRes.ok) {
          const products = (await skuRes.json()) as ProductWithImages[];
          if (Array.isArray(products) && products.length > 0) {
            product = products[0] || null;
          }
        }
      }

      if (!product) {
        throw new Error(`Product not found: ${testProductId}`);
      }

      const uploadedImages = Array.isArray(product.images) 
        ? product.images.map((img: ProductImageRecord) => img.imageFile?.filepath).filter((p: string | undefined): p is string => Boolean(p)) 
        : [];
      const externalImages = Array.isArray(product.imageLinks) ? product.imageLinks : [];
      const allImageUrls = [...externalImages, ...uploadedImages];

      // Create a job for the test
      const enqueueRes = await fetch("/api/products/ai-jobs/enqueue", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          productId: product.id,
          type: "description_generation",
          payload: {
            productData: product,
            imageUrls: allImageUrls,
            visionOutputEnabled,
            generationOutputEnabled,
            isTest: true
          }
        }),
      });

      const enqueueData = (await enqueueRes.json()) as { error?: string; jobId: string };
      if (!enqueueRes.ok) {
        throw new Error(enqueueData.error || "Failed to enqueue test job.");
      }
      const jobId = enqueueData.jobId;

      // Poll for completion
      let completed = false;
      let attempts = 0;
      while (!completed && attempts < 60) { // 2 minutes max
        await new Promise((r: (value: void) => void) => setTimeout(r, 2000));
        const statusRes = await fetch(`/api/products/ai-jobs/${jobId}`);
        if (!statusRes.ok) break;
        const { job } = (await statusRes.json()) as { job: JobData };

        if (job.status === "completed") {
          const data = job.result;

          const newTestResult: TestResultData = {
            analysisInitial: data?.analysisInitial || data?.analysis || "",
            analysisFinal: data?.analysisFinal || "",
            descriptionInitial: data?.descriptionInitial || data?.description || "",
            descriptionFinal: data?.descriptionFinal || "",
          };

          setTestResult(newTestResult);

          // Save test result to database so it persists across page navigations
          try {
            await fetch("/api/settings", {
              method: "POST",
              headers: { "Content-Type": "application/json" },
              body: JSON.stringify({
                key: "ai_description_last_test_result",
                value: JSON.stringify(newTestResult)
              }),
            });
            invalidateSettingsCache();
          } catch (err) {
            logClientError(err, { context: { source: "AiDescriptionSettings", action: "saveTestResult", jobId } });
          }

          toast("Test completed. Results saved.", { variant: "success" });
          completed = true;
        } else if (job.status === "failed") {
          throw new Error(job.errorMessage || "Job failed.");
        } else if (job.status === "canceled") {
          throw new Error("Job was canceled.");
        }
        attempts++;
      }

      if (!completed) {
        throw new Error("Test timed out. Check the Jobs page.");
      }

    } catch (error) {
      logClientError(error, { context: { source: "AiDescriptionSettings", action: "handleTest", productId: testProductId } });
      toast(error instanceof Error ? error.message : "Test failed.", { variant: "error" });
    } finally {
      setTesting(false);
    }
  };

  const handleQueueAll = async (): Promise<void> => {
    if (!window.confirm("This will queue description generation for ALL products using the current configuration. Proceed?")) return;
    setQueuing(true);
    try {
      const res = await fetch("/api/products/ai-jobs/bulk", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          type: "description_generation",
          config: {
            visionOutputEnabled,
            generationOutputEnabled
          }
        }),
      });
      if (!res.ok) throw new Error("Failed to queue jobs.");
      const data = (await res.json()) as { count: number };
      toast(`Queued ${data.count} products for generation.`, { variant: "success" });
    } catch (error) {
      toast(error instanceof Error ? error.message : "Failed to queue jobs.", { variant: "error" });
    } finally {
      setQueuing(false);
    }
  };

  const handleSave = async (): Promise<void> => {
    setSaving(true);
    try {
      const payloads = [
        { key: "ai_vision_model", value: imageAnalysisModel },
        { key: "ai_vision_user_prompt", value: visionInputPrompt },
        { key: "ai_vision_prompt", value: visionOutputPrompt },
        { key: "ai_vision_output_enabled", value: String(visionOutputEnabled) },
        { key: "openai_model", value: descriptionGenerationModel },
        { key: "description_generation_user_prompt", value: generationInputPrompt },
        { key: "description_generation_prompt", value: generationOutputPrompt },
        { key: "ai_generation_output_enabled", value: String(generationOutputEnabled) },
        { key: "ai_description_test_product_id", value: testProductId },
      ];

      // Use TanStack Query mutation for settings updates
      for (const payload of payloads) {
        await updateSettingMutateAsync(payload);
      }

      // Also save to dedicated MongoDB collection
      await fetch("/api/ai-config", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          imageAnalysisModel,
          visionInputPrompt,
          visionOutputPrompt,
          visionOutputEnabled,
          descriptionGenerationModel,
          generationInputPrompt,
          generationOutputPrompt,
          generationOutputEnabled,
          testProductId,
        }),
      });

      toast("Settings saved.", { variant: "success" });
    } catch (error) {
      logClientError(error, { context: { source: "AiDescriptionSettings", action: "handleSave" } });
      toast("Failed to save.", { variant: "error" });
    } finally {
      setSaving(false);
    }
  };

  const copyResult = (text?: string): void => {
    if (!text) return;
    void navigator.clipboard.writeText(text);
    toast("Result copied to clipboard.");
  };

  const clearTestResults = async (): Promise<void> => {
    setTestResult(null);
    try {
      await fetch("/api/settings", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          key: "ai_description_last_test_result",
          value: ""
        }),
      });
      invalidateSettingsCache();
      toast("Test results cleared.", { variant: "success" });
    } catch (err) {
      console.warn("Failed to clear test results from database:", err);
    }
  };

  if (loading) return <div className="text-sm text-gray-400">Loading settings...</div>;

  return (
    <SettingsPageLayout
      title="AI Description Configuration"
      description="Configure multi-step generation flow for product descriptions."
      onSave={handleSave}
      isSaving={saving}
      actions={
        <>
          <Input
            placeholder="Product ID or SKU"
            value={testProductId}
            onChange={(e: React.ChangeEvent<HTMLInputElement>) => setTestProductId(e.target.value)}
            className="w-[180px] bg-gray-900 border text-white h-9 text-sm"
          />
          <Button variant="secondary" onClick={() => void handleTest()} disabled={testing} className="gap-2 h-9">
            <PlayIcon className="size-3.5" />
            {testing ? "Testing..." : "Test on Product"}
          </Button>

          {testResult && (
            <Button variant="ghost" onClick={() => void clearTestResults()} className="gap-2 h-9 text-red-400 hover:text-red-300">
              <XCircle className="size-3.5" />
              Clear Results
            </Button>
          )}

          <Button variant="outline" onClick={() => void handleQueueAll()} disabled={queuing} className="gap-2 h-9 text-purple-400 border-purple-900/50 hover:bg-purple-950">
            <RefreshCcw className={`size-3.5 ${queuing ? "animate-spin" : ""}`} />
            {queuing ? "Queuing..." : "Queue for All"}
          </Button>

          <Dialog>
            <DialogTrigger asChild>
              <Button variant="outline" className="h-9 gap-2">
                <InfoIcon className="size-4" />
                Placeholders
              </Button>
            </DialogTrigger>
            <DialogContent className="max-w-md max-h-[80vh] overflow-y-auto">
              <DialogHeader>
                <DialogTitle>Available Placeholders</DialogTitle>
                <DialogDescription>Use these placeholders to inject dynamic data into your prompts.</DialogDescription>
              </DialogHeader>
              <div className="space-y-2 mt-4">
                {AVAILABLE_PLACEHOLDERS.map((ph: { key: string, description: string }) => (
                  <div key={ph.key} className="flex items-center justify-between text-sm border-b border-border/50 pb-2 last:border-0 last:pb-0">
                    <code className="text-purple-400 font-bold bg-purple-500/10 px-1 py-0.5 rounded">[{ph.key}]</code>
                    <span className="text-gray-500 italic text-xs">{ph.description}</span>
                  </div>
                ))}
              </div>
            </DialogContent>
          </Dialog>
        </>
      }
    >
      <div className="space-y-8">
        {/* Path 1 */}
        <div className="space-y-4">
          <div className="flex items-center gap-2">
            <Badge variant="info" className="h-6 w-6 justify-center p-0 font-bold">1</Badge>
            <h3 className="text-md font-medium text-white">Signal Path 1: Image Analysis</h3>
          </div>

          <div className="pl-8 space-y-6">
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
              <div className="space-y-2">
                <Label>Input Prompt</Label>
                <Textarea
                  rows={4}
                  value={visionInputPrompt}
                  onChange={(e: React.ChangeEvent<HTMLTextAreaElement>) => setVisionInputPrompt(e.target.value)}
                  className="mt-1.5 bg-gray-900 border text-white font-mono text-sm"
                />
              </div>
              <div className="space-y-2">
                <div className="flex items-center justify-between">
                  <Label>Initial Result</Label>
                  <Button variant="ghost" size="sm" className="h-6 text-[10px]" onClick={() => copyResult(testResult?.analysisInitial)}>
                    <CopyIcon className="size-3 mr-1"/>Copy
                  </Button>
                </div>
                <SectionPanel variant="subtle" className="mt-1.5 p-4 text-sm text-gray-300 h-[100px] overflow-y-auto border border-border font-mono">
                  {testResult?.analysisInitial ? (
                    <div className="whitespace-pre-wrap">{testResult.analysisInitial}</div>
                  ) : (
                    <span className="text-gray-600 italic text-xs">No result yet.</span>
                  )}
                </SectionPanel>
              </div>
            </div>

            <div className="max-w-md">
              <Label>Vision Model</Label>
              <UnifiedSelect
                value={imageAnalysisModel}
                onValueChange={setImageAnalysisModel}
                options={[...STATIC_VISION_MODELS, ...ollamaModels]}
              />
            </div>

            <div className="pt-4 border-t border-border/50 space-y-4">
              <div className="flex items-center gap-2">
                <Checkbox 
                  id="v-output-enabled" 
                  checked={visionOutputEnabled} 
                  onCheckedChange={(checked: boolean | "indeterminate") => setVisionOutputEnabled(!!checked)} 
                />
                <Label htmlFor="v-output-enabled" className="text-blue-400 cursor-pointer">Enable Output Prompt (Refinement using {imageAnalysisModel})</Label>
              </div>
              {visionOutputEnabled && (
                <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 animate-in fade-in slide-in-from-top-2 duration-300">
                  <div className="space-y-2">
                    <Label>Output Prompt</Label>
                    <Textarea
                      rows={4}
                      value={visionOutputPrompt}
                      onChange={(e: React.ChangeEvent<HTMLTextAreaElement>) => setVisionOutputPrompt(e.target.value)}
                      className="mt-1.5 bg-gray-900 border text-white font-mono text-sm"
                      placeholder="Refine result... use [result] for initial analysis."
                    />
                  </div>
                  <div className="space-y-2">
                    <div className="flex items-center justify-between">
                      <Label>Final Analysis</Label>
                      <Button variant="ghost" size="sm" className="h-6 text-[10px]" onClick={() => copyResult(testResult?.analysisFinal)}>
                        <CopyIcon className="size-3 mr-1"/>Copy
                      </Button>
                    </div>
                    <SectionPanel variant="subtle" className="mt-1.5 p-4 text-sm text-gray-300 h-[100px] overflow-y-auto border border-border font-mono">
                      {testResult?.analysisFinal ? (
                        <div className="whitespace-pre-wrap">{testResult.analysisFinal}</div>
                      ) : (
                        <span className="text-gray-600 italic text-xs">No result yet.</span>
                      )}
                    </SectionPanel>
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>

        <div className="border-t border-border my-8"></div>

        {/* Path 2 */}
        <div className="space-y-4">
          <div className="flex items-center gap-2">
            <Badge variant="secondary" className="h-6 w-6 justify-center p-0 font-bold border-purple-500/30 bg-purple-500/20 text-purple-400">2</Badge>
            <h3 className="text-md font-medium text-white">Signal Path 2: Description Generation</h3>
          </div>

          <div className="pl-8 space-y-6">
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
              <div className="space-y-2">
                <Label>Input Prompt</Label>
                <Textarea
                  rows={6}
                  value={generationInputPrompt}
                  onChange={(e: React.ChangeEvent<HTMLTextAreaElement>) => setGenerationInputPrompt(e.target.value)}
                  className="mt-1.5 bg-gray-900 border text-white font-mono text-sm"
                />
              </div>
              <div className="space-y-2">
                <div className="flex items-center justify-between">
                  <Label>Initial Description</Label>
                  <Button variant="ghost" size="sm" className="h-6 text-[10px]" onClick={() => copyResult(testResult?.descriptionInitial)}>
                    <CopyIcon className="size-3 mr-1"/>Copy
                  </Button>
                </div>
                <SectionPanel variant="subtle" className="mt-1.5 p-4 text-sm text-gray-300 h-[132px] overflow-y-auto border border-border font-sans">
                  {testResult?.descriptionInitial ? (
                    <div className="whitespace-pre-wrap">{testResult.descriptionInitial}</div>
                  ) : (
                    <span className="text-gray-600 italic text-xs">No result yet.</span>
                  )}
                </SectionPanel>
              </div>
            </div>

            <div className="max-w-md">
              <Label>Generation Model</Label>
              <UnifiedSelect
                value={descriptionGenerationModel}
                onValueChange={setDescriptionGenerationModel}
                options={[...STATIC_TEXT_MODELS, ...ollamaModels]}
              />
            </div>

            <div className="pt-4 border-t border-border/50 space-y-4">
              <div className="flex items-center gap-2">
                <Checkbox 
                  id="g-output-enabled" 
                  checked={generationOutputEnabled} 
                  onCheckedChange={(checked: boolean | "indeterminate") => setGenerationOutputEnabled(!!checked)} 
                />
                <Label htmlFor="g-output-enabled" className="text-purple-400 cursor-pointer">Enable Output Prompt (Refinement using {descriptionGenerationModel})</Label>
              </div>
              {generationOutputEnabled && (
                <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 animate-in fade-in slide-in-from-top-2 duration-300">
                  <div className="space-y-2">
                    <Label>Output Prompt</Label>
                    <Textarea
                      rows={6}
                      value={generationOutputPrompt}
                      onChange={(e: React.ChangeEvent<HTMLTextAreaElement>) => setGenerationOutputPrompt(e.target.value)}
                      className="mt-1.5 bg-gray-900 border text-white font-mono text-sm"
                      placeholder="Final polish... use [result] for initial description."
                    />
                  </div>
                  <div className="space-y-2">
                    <div className="flex items-center justify-between">
                      <Label>Final Description</Label>
                      <Button variant="ghost" size="sm" className="h-6 text-[10px]" onClick={() => copyResult(testResult?.descriptionFinal)}>
                        <CopyIcon className="size-3 mr-1"/>Copy
                      </Button>
                    </div>
                    <SectionPanel variant="subtle" className="mt-1.5 p-4 text-sm text-gray-300 h-[132px] overflow-y-auto border border-border font-sans">
                      {testResult?.descriptionFinal ? (
                        <div className="whitespace-pre-wrap">{testResult.descriptionFinal}</div>
                      ) : (
                        <span className="text-gray-600 italic text-xs">No result yet.</span>
                      )}
                    </SectionPanel>
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
    </SettingsPageLayout>
  );
}

"use client";

import { useState, useRef, useMemo } from "react";
import { useQuery } from "@tanstack/react-query";
import { logger } from "@/shared/utils/logger";
import type { Catalog } from "@/features/products/types";
import type { PriceGroupWithDetails } from "@/features/products/types";

type LanguageRecord = { id: string; code: string; name: string };
type LanguageOption = {
  value: "name_en" | "name_pl" | "name_de";
  label: string;
};
type CurrencyRecord = { code?: string | null };

const supportedLanguageMap: Record<string, LanguageOption> = {
  EN: { value: "name_en", label: "English" },
  PL: { value: "name_pl", label: "Polish" },
  DE: { value: "name_de", label: "German" },
};

// Query keys for cache management
const catalogSyncQueryKeys = {
  catalogs: ["catalogs"] as const,
  priceGroups: ["price-groups"] as const,
  languages: ["languages"] as const,
  currencies: ["currencies"] as const,
};

// API fetch functions
async function fetchCatalogs(): Promise<Catalog[]> {
  const res = await fetch("/api/catalogs");
  if (!res.ok) {
    const payload = (await res.json()) as { error?: string };
    throw new Error(payload?.error || "Failed to load catalogs");
  }
  return res.json() as Promise<Catalog[]>;
}

async function fetchPriceGroups(): Promise<PriceGroupWithDetails[]> {
  const res = await fetch("/api/price-groups");
  if (!res.ok) {
    throw new Error("Failed to load price groups");
  }
  return res.json() as Promise<PriceGroupWithDetails[]>;
}

async function fetchLanguages(): Promise<LanguageRecord[]> {
  const res = await fetch("/api/languages");
  if (!res.ok) {
    throw new Error("Failed to load languages");
  }
  return res.json() as Promise<LanguageRecord[]>;
}

async function fetchCurrencies(): Promise<CurrencyRecord[]> {
  const res = await fetch("/api/currencies");
  if (!res.ok) {
    throw new Error("Failed to load currencies");
  }
  return res.json() as Promise<CurrencyRecord[]>;
}

export function useCatalogSync(catalogFilter: string): { catalogs: Catalog[]; catalogsLoading: boolean; catalogsError: string | null; currencyCode: string; setCurrencyCode: (action: string | ((prev: string) => string)) => void; currencyOptions: string[]; priceGroups: PriceGroupWithDetails[]; catalogFilterInitialized: React.MutableRefObject<boolean>; languageOptions: LanguageOption[]; fallbackNameLocale: "name_en" | "name_pl" | "name_de" | undefined; } {
  const catalogFilterInitialized = useRef(false);

  // Parallel queries for all data sources
  const catalogsQuery = useQuery({
    queryKey: catalogSyncQueryKeys.catalogs,
    queryFn: fetchCatalogs,
    staleTime: 1000 * 60 * 5, // 5 minutes
  });

  const priceGroupsQuery = useQuery({
    queryKey: catalogSyncQueryKeys.priceGroups,
    queryFn: fetchPriceGroups,
    staleTime: 1000 * 60 * 5,
  });

  const languagesQuery = useQuery({
    queryKey: catalogSyncQueryKeys.languages,
    queryFn: fetchLanguages,
    staleTime: 1000 * 60 * 5,
  });

  const currenciesQuery = useQuery({
    queryKey: catalogSyncQueryKeys.currencies,
    queryFn: fetchCurrencies,
    staleTime: 1000 * 60 * 5,
  });

  // Log errors
  if (catalogsQuery.error) {
    logger.error("Failed to load catalogs:", catalogsQuery.error);
  }
  if (priceGroupsQuery.error) {
    logger.error("Failed to load price groups:", priceGroupsQuery.error);
  }
  if (languagesQuery.error) {
    logger.error("Failed to load languages:", languagesQuery.error);
  }
  if (currenciesQuery.error) {
    logger.error("Failed to load currencies:", currenciesQuery.error);
  }

  // Extract data with defaults
  const rawCatalogs = useMemo(
    () => catalogsQuery.data ?? [],
    [catalogsQuery.data],
  );
  const priceGroups = useMemo(
    () => priceGroupsQuery.data ?? [],
    [priceGroupsQuery.data],
  );
  const languages = useMemo(
    () => languagesQuery.data ?? [],
    [languagesQuery.data],
  );
  const currencyPriceGroups = priceGroups;

  // Compute allowed currency codes
  const allowedCurrencyCodes = useMemo(() => {
    const data = currenciesQuery.data ?? [];
    return data
      .map((entry) => entry.code?.trim().toUpperCase())
      .filter((code): code is string => Boolean(code));
  }, [currenciesQuery.data]);

  // Memoize catalog transformation to prevent new references
  const catalogs = useMemo(
    () =>
      rawCatalogs.map((catalog) => ({
        ...catalog,
        priceGroupIds: catalog.priceGroupIds ?? [],
        defaultPriceGroupId: catalog.defaultPriceGroupId ?? null,
      })),
    [rawCatalogs],
  );

  // Memoize currency options to prevent unnecessary re-renders
  const { codes, fallbackCode } = useMemo((): { codes: string[]; fallbackCode: string } => {
    if (currencyPriceGroups.length === 0)
      return { codes: [] as string[], fallbackCode: "" };

    const isCatalogScoped =
      catalogFilter !== "all" && catalogFilter !== "unassigned";
    const catalog = isCatalogScoped
      ? catalogs.find((entry) => entry.id === catalogFilter)
      : undefined;
    const catalogPriceGroupIds = catalog?.priceGroupIds ?? [];
    const allowedGroupIds =
      catalogPriceGroupIds.length > 0 ? new Set(catalogPriceGroupIds) : null;

    const candidateGroups = allowedGroupIds
      ? currencyPriceGroups.filter((group) => allowedGroupIds.has(group.id))
      : currencyPriceGroups;

    let codes = Array.from(
      new Set(
        candidateGroups
          .map((group) => group.currency?.code)
          .filter((code): code is NonNullable<typeof code> => Boolean(code)),
      ),
    ).map((code) => code.trim().toUpperCase());

    const allowedSet = new Set(
      allowedCurrencyCodes.map((code) => code.trim().toUpperCase()),
    );
    if (allowedSet.size > 0) {
      codes = codes.filter((code) => allowedSet.has(code));
    } else {
      // Basic safety filter if no allowed list available.
      codes = codes.filter((code) => /^[A-Z]{3,5}$/.test(code));
    }

    const defaultGroupId = catalog?.defaultPriceGroupId ?? null;
    const defaultGroup = defaultGroupId
      ? candidateGroups.find((group) => group.id === defaultGroupId)
      : candidateGroups.find((group) => group.isDefault);

    const fallbackCode = defaultGroup?.currency?.code || codes[0] || "";

    return { codes, fallbackCode };
  }, [catalogFilter, catalogs, currencyPriceGroups, allowedCurrencyCodes]);

  // Sync Currency Options based on Catalog
  const currencyOptions = codes;

  // Derived state for currencyCode to avoid set-state-in-effect
  // If the current user selection is valid for the current catalog, keep it.
  // Otherwise, fallback to the catalog's default.
  // We use a piece of state to track the user's *explicit* selection if any.
  // Note: We use 'currencyCode' state here to track the *effective* code if possible,
  // but to match the "derived" pattern we need to know if the state value is "stale".
  // Actually, the simplest way is to just let the user set a preference, and validate it on read.
  const [userCurrencyCode, setUserCurrencyCode] = useState<string | null>(null);

  const currencyCode =
    userCurrencyCode && codes.includes(userCurrencyCode)
      ? userCurrencyCode
      : fallbackCode;

  const setCurrencyCode = (action: string | ((prev: string) => string)) => {
    // Wrap the setter to handle functional updates correctly with the derived value
    if (typeof action === "function") {
      setUserCurrencyCode((_prev) => {
        // We use the *derived* currencyCode as the base for the update
        const newVal = action(currencyCode);
        return newVal;
      });
    } else {
      setUserCurrencyCode(action);
    }
  };

  const { languageOptions, fallbackNameLocale } = useMemo((): { languageOptions: LanguageOption[]; fallbackNameLocale: "name_en" | "name_pl" | "name_de" | undefined } => {
    const options: LanguageOption[] = [];
    const isCatalogScoped =
      catalogFilter !== "all" && catalogFilter !== "unassigned";
    const catalog = isCatalogScoped
      ? catalogs.find((entry) => entry.id === catalogFilter)
      : undefined;
    const allowedIds = catalog?.languageIds ?? [];

    const scopedLanguages =
      allowedIds.length > 0
        ? languages.filter((lang) => allowedIds.includes(lang.id))
        : languages;

    const seen = new Set<string>();
    scopedLanguages.forEach((lang) => {
      const key = lang.code?.trim().toUpperCase();
      const option = supportedLanguageMap[key];
      if (!option || seen.has(option.value)) return;
      seen.add(option.value);
      options.push(option);
    });

    if (options.length === 0) {
      options.push(supportedLanguageMap.EN!);
      options.push(supportedLanguageMap.PL!);
      options.push(supportedLanguageMap.DE!);
    }

    const defaultLanguageId = catalog?.defaultLanguageId ?? null;
    const defaultLang = defaultLanguageId
      ? languages.find((lang) => lang.id === defaultLanguageId)
      : null;
    const defaultOption = defaultLang
      ? supportedLanguageMap[defaultLang.code?.trim().toUpperCase() || ""]
      : undefined;
    const fallbackNameLocale = defaultOption?.value ?? options[0]?.value;

    return { languageOptions: options, fallbackNameLocale };
  }, [catalogFilter, catalogs, languages]);

  return {
    catalogs,
    catalogsLoading: catalogsQuery.isLoading,
    catalogsError: catalogsQuery.error ? catalogsQuery.error.message : null,
    currencyCode,
    setCurrencyCode,
    currencyOptions,
    priceGroups,
    catalogFilterInitialized,
    languageOptions,
    fallbackNameLocale,
  };
}

"use client";

import { useNormalizedQuery, useComposedQuery } from "@/shared/hooks/useQueryComposition";
import { useQueryScheduler, useBackgroundQueries } from "@/shared/hooks/useQueryScheduler";
import { useAdaptiveQuery } from "@/shared/hooks/query/useSmartCache";
import { useEffect } from "react";

// Enhanced product queries with normalization and composition
export function useEnhancedProducts(): ReturnType<typeof useNormalizedQuery> {
  const scheduler = useQueryScheduler();

  // Normalized products query
  const productsQuery = useNormalizedQuery(
    ['products', 'enhanced'],
    async (): Promise<any[]> => {
      const res = await fetch('/api/products');
      return res.json() as Promise<any[]>;
    }
  );

  // Composed query for product statistics
  const productStats = useComposedQuery(
    {
      queryKey: ['products', 'enhanced'],
      queryFn: async (): Promise<any[]> => {
        const res = await fetch('/api/products');
        return res.json() as Promise<any[]>;
      },
    },
    (products: any[]): { total: number; published: number; categories: number; avgPrice: number; } => ({
      total: products.length,
      published: products.filter((p: any) => p.published).length,
      categories: [...new Set(products.map((p: any) => p.category))].length,
      avgPrice: products.reduce((sum: number, p: any) => sum + (p.price || 0), 0) / products.length,
    })
  );

  // Schedule related queries
  useEffect(() => {
    scheduler.scheduleQuery(
      'product-categories',
      ['products', 'categories'],
      async () => {
        const catalogsRes = await fetch("/api/catalogs");
        if (!catalogsRes.ok) return [];
        const catalogs = (await catalogsRes.json()) as Array<{ id?: string }>;
        const catalogId = Array.isArray(catalogs) ? catalogs[0]?.id : undefined;
        if (!catalogId) return [];
        const res = await fetch(
          `/api/products/categories?catalogId=${encodeURIComponent(catalogId)}`
        );
        if (!res.ok) return [];
        return res.json();
      },
      { priority: 'medium', delay: 2000 }
    );

    scheduler.scheduleQuery(
      'product-tags',
      ['products', 'tags'],
      async () => {
        const res = await fetch('/api/products/tags');
        return res.json();
      },
      { priority: 'low', delay: 5000 }
    );
  }, [scheduler]);

  // Background sync for critical data
  useBackgroundQueries([
    {
      queryKey: ['products', 'count'],
      queryFn: async () => {
        const res = await fetch('/api/products/count');
        return res.json();
      },
      interval: 60000, // 1 minute
    },
  ]);

  return {
    products: productsQuery,
    stats: productStats,
    selectById: productsQuery.selectById,
    selectMany: productsQuery.selectMany,
  };
}

// Enhanced user management with adaptive caching
export function useEnhancedUsers(): { users: ReturnType<typeof useAdaptiveQuery>; permissions: ReturnType<typeof useAdaptiveQuery>; activity: ReturnType<typeof useAdaptiveQuery>; } {
  // User list with long-term caching
  const users = useAdaptiveQuery(
    ['users', 'list'],
    async () => {
      const res = await fetch('/api/users');
      return res.json();
    },
    { dataType: 'longTerm', priority: 'medium' }
  );

  // User permissions with standard caching
  const permissions = useAdaptiveQuery(
    ['users', 'permissions'],
    async () => {
      const res = await fetch('/api/users/permissions');
      return res.json();
    },
    { dataType: 'standard', priority: 'high' }
  );

  // User activity with real-time updates
  const activity = useAdaptiveQuery(
    ['users', 'activity'],
    async () => {
      const res = await fetch('/api/users/activity');
      return res.json();
    },
    { dataType: 'realtime', priority: 'low' }
  );

  return { users, permissions, activity };
}

// Enhanced settings with composition
export function useEnhancedSettings(): ReturnType<typeof useComposedQuery> {
  // Compose all settings into a single object
  const settings = useComposedQuery(
    {
      queryKey: ['settings', 'all'],
      queryFn: async () => {
        const [app, user, system] = await Promise.all([
          fetch('/api/settings/app').then(r => r.json()),
          fetch('/api/settings/user').then(r => r.json()),
          fetch('/api/settings/system').then(r => r.json()),
        ]);
        return { app, user, system };
      },
    },
    (data) => ({
      ...data.app,
      ...data.user,
      system: data.system,
      theme: data.user.theme || data.app.defaultTheme,
      language: data.user.language || data.app.defaultLanguage,
    })
  );

  return settings;
}

