"use client";

import { Button, Tag } from "@/shared/ui"; // SectionPanel removed
import { Box, Eye, Edit2, Trash2, Loader2, Globe, Lock } from "lucide-react";
import type { Asset3DRecord } from "../types";
import { cn } from "@/shared/utils";
import { CardWithActions } from "@/shared/components/CardWithActions"; // Added import

export interface Asset3DCardProps {
  asset: Asset3DRecord;
  onPreview: (asset: Asset3DRecord) => void;
  onEdit: (asset: Asset3DRecord) => void;
  onDelete: (asset: Asset3DRecord) => void;
  isDeleting?: boolean;
  className?: string;
}

export function Asset3DCard({
  asset,
  onPreview,
  onEdit,
  onDelete,
  isDeleting = false,
  className,
}: Asset3DCardProps): React.JSX.Element {
  const formatFileSize = (bytes: number): string => {
    if (bytes < 1024) return `${bytes} B`;
    if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
    return `${(bytes / 1024 / 1024).toFixed(2)} MB`;
  };

  const formatDate = (date: Date | string): string => {
    return new Date(date).toLocaleDateString("en-US", {
      year: "numeric",
      month: "short",
      day: "numeric",
    });
  };

  const displayName = asset.name || asset.filename.replace(/^\d+-/, "");

  const descriptionProps = asset.description ? { description: asset.description } : {};
  const classNameProps = className ? { className } : {};

  return (
    <CardWithActions
      title={displayName}
      {...descriptionProps}
      {...classNameProps}
      onClick={(): void => onPreview(asset)}
      actions={
        <div className="flex items-center gap-1">
          <Button
            variant="ghost"
            size="icon"
            className="h-7 w-7 text-muted-foreground hover:text-blue-400"
            onClick={(e: React.MouseEvent): void => {
              e.stopPropagation();
              onEdit(asset);
            }}
          >
            <Edit2 className="h-4 w-4" />
          </Button>
          <Button
            variant="ghost"
            size="icon"
            className="h-7 w-7 text-muted-foreground hover:text-red-400"
            onClick={(e: React.MouseEvent): void => {
              e.stopPropagation();
              onDelete(asset);
            }}
            disabled={isDeleting}
          >
            {isDeleting ? (
              <Loader2 className="h-4 w-4 animate-spin" />
            ) : (
              <Trash2 className="h-4 w-4" />
            )}
          </Button>
        </div>
      }
    >
      {/* Preview Area (original content, slightly adjusted) */}
      <div
        className="h-40 bg-muted/30 p-0 flex items-center justify-center cursor-pointer relative"
      >
        <div className="flex flex-col items-center gap-2 text-muted-foreground group-hover:text-blue-400 transition-colors">
          <Box className="h-12 w-12" />
          <span className="text-xs flex items-center gap-1">
            <Eye className="h-3 w-3" />
            Click to preview
          </span>
        </div>

        {/* Visibility Badge */}
        <div
          className={cn(
            "absolute top-2 right-2 px-2 py-1 rounded text-xs flex items-center gap-1",
            asset.isPublic
              ? "bg-emerald-500/10 text-emerald-400"
              : "bg-muted text-muted-foreground",
          )}
        >
          {asset.isPublic ? (
            <>
              <Globe className="h-3 w-3" />
              Public
            </>
          ) : (
            <>
              <Lock className="h-3 w-3" />
              Private
            </>
          )}
        </div>

        {/* Category Badge */}
        {asset.category && (
          <div className="absolute top-2 left-2 px-2 py-1 rounded text-xs bg-blue-500/10 text-blue-300">
            {asset.category}
          </div>
        )}
      </div>

      {/* Tags (original content) */}
      {asset.tags.length > 0 && (
        <div className="flex flex-wrap gap-1 mt-2">
          {asset.tags.slice(0, 3).map((tag: string) => (
            <Tag
              key={tag}
              label={tag}
              className="bg-muted text-muted-foreground"
            />
          ))}
          {asset.tags.length > 3 && (
            <Tag
              label={`+${asset.tags.length - 3}`}
              className="bg-muted text-muted-foreground"
            />
          )}
        </div>
      )}

      {/* Metadata (original content) */}
      <div className="flex items-center justify-between p-3 pt-0 mt-0">
        <div className="text-xs text-muted-foreground">
          <span>{formatFileSize(asset.size)}</span>
          <span className="mx-1">•</span>
          <span>{formatDate(asset.createdAt)}</span>
        </div>
      </div>
    </CardWithActions>
  );
}

